package nc;

import java.util.PriorityQueue;

public class PriorityQueues {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		PriorityQueue pq = new PriorityQueue();
		pq.add(18);
		pq.add(45);
		pq.add(54);
		pq.add(164);
		pq.add(67);
		pq.add(-144);
		pq.add(58);
		pq.add(107);
		pq.add(-11);
		pq.add(1);
		pq.add(50);
		System.out.println(pq);
	}

}
